```javascript
function isPrime(num) {
  if (num <= 1) return false;
  if (num <= 3) return true;

  if (num % 2 === 0 || num % 3 === 0) return false;

  for (let i = 5; i * i <= num; i += 6) {
    if (num % i === 0 || num % (i + 2) === 0) return false;
  }

  return true;
}

function checkPrimes(arr) {
  if (arr.length < 5) {
    console.log("Array must contain exactly 5 numbers.");
    return;
  }

  for (const num of arr) {
    if (isPrime(num)) {
      console.log(num);
    }
  }
}

// Example usage:
const numbers = [4, 7, 10, 23, 11];
checkPrimes(numbers);
```

In this code:
- The `isPrime` function checks if a given number is prime.
- The `checkPrimes` function takes an array of numbers and calls `isPrime` for each number in the array. If a number is prime, it prints the number to the console.

You can use this function with any array of 5 numbers to check for prime numbers.

